import { useFrame } from "@react-three/fiber";
import { Physics, PhysicsManager } from "./PhysicsEngine";
import { useGameStore, upgradeTimers } from "./store";
import { SoundManager } from "../Effects/SoundManager";
import { useWorld } from "./GameWorldContext";
import { PHYSICS_DELTA_CAP, GRID_WATER_KILL_X } from "./constants";

export default function GlobalLoop() {
    const world = useWorld();
    const prevCurZ = { current: null }; // module-ref для кеширования позиции по Z

    useFrame((_state, rawDelta) => {
        const delta = Math.min(rawDelta, PHYSICS_DELTA_CAP);
        const {
            isDead, isPaused, upgradeMenuOpen,
            isInvulnerable, invulnerabilityActive, isMoving,
            die, flash, shieldHit,
            getSpeedMultiplier,
            collectCoin, collectPartMedal,
            slowMotionActive, scoreBoostActive,
        } = useGameStore.getState();

        if (isDead || isPaused || upgradeMenuOpen) return;

        const player = world.playerRef?.current;
        if (!player) return;

        const pPos = player.position;
        const curZ = Math.round(pPos.z);

        const speedMul = slowMotionActive ? getSpeedMultiplier() * 0.5 : getSpeedMultiplier();
        Physics.update(world, delta, speedMul);

        // ── Таймеры апгрейдов: проверяем истечение, set() только при смене ─────
        const now = performance.now();
        if (slowMotionActive && upgradeTimers.slowMotionEndAt && now >= upgradeTimers.slowMotionEndAt) {
            upgradeTimers.slowMotionEndAt = 0;
            useGameStore.setState({ slowMotionActive: false });
        }
        if (scoreBoostActive && upgradeTimers.scoreBoostEndAt && now >= upgradeTimers.scoreBoostEndAt) {
            upgradeTimers.scoreBoostEndAt = 0;
            useGameStore.setState({ scoreBoostActive: false });
        }

        // Гранаты
        const hitGrenade = Physics.checkGrenadeHit(world);
        if (hitGrenade) {
            const isLethal = hitGrenade.type !== 'Flash';
            if (invulnerabilityActive && isLethal) {
                // Щит поглощает только смертельный удар; Flash проходит сквозь
                PhysicsManager.hideObstacle(hitGrenade.id);
                shieldHit();
            } else if (!isInvulnerable) {
                PhysicsManager.hideObstacle(hitGrenade.id);
                if (hitGrenade.type === 'Flash') {
                    flash();
                    SoundManager.play('flash');
                    SoundManager.playDeafening();
                    hitGrenade.x = hitGrenade.direction > 0 ? 15 : -15;
                } else {
                    die(hitGrenade.type, [hitGrenade.x, 0.5, hitGrenade.z]);
                }
                return;
            }
        }

        // Монеты
        const coin = Physics.checkCoinPickup(world);
        if (coin) {
            coin.collected = true;
            collectCoin(coin.type);
            SoundManager.playCoin(coin.type === 'red');
        }

        // Медали (только части, special medals убраны с карты)
        const medal = Physics.checkMedalPickup(world);
        if (medal) {
            const subtype = medal.subtype ?? 'medal_part1';
            for (const m of world.medals) {
                if ((m.subtype ?? 'medal_part1') === subtype) m.collected = true;
            }
            const completed = collectPartMedal(subtype);
            SoundManager.play(completed ? 'medalPowerup' : 'medalCollect');
        }

        // Звук воды — пересчёт только при смене строки
        if (curZ !== prevCurZ.current) {
            prevCurZ.current = curZ;
            let minWaterDist = Infinity;
            for (const wz of world.waters) {
                const d = Math.abs(curZ - wz);
                if (d < minWaterDist) minWaterDist = d;
            }
            SoundManager.setWaterAmbient(Math.max(0, 1 - minWaterDist / 4) * 0.65);
        }

        // Утопление — вода всегда убивает (неуязвимость не защищает)
        const isOnWater = world.waters.has(curZ);
        if (isOnWater) {
            // Уехал за край карты по X — немедленное утопление
            if (Math.abs(pPos.x) > GRID_WATER_KILL_X) {
                die('Drown', [pPos.x, -0.5, pPos.z]);
                return;
            }
            // Нет бревна и нет кувшинки — тонем
            if (!isMoving) {
                const currentLog  = Physics.getLogUnderPlayer(world);
                const currentLily = Physics.getLilyUnderPlayer(world);
                if (!currentLog && !currentLily) {
                    die('Drown', [pPos.x, -0.5, pPos.z]);
                }
            }
        }
    });

    return null;
}
