import { useEffect, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { useGameStore } from '../Logic/store';
import { useWorld } from '../Logic/GameWorldContext';
import { SoundManager } from '../Effects/SoundManager';
import {
    BOMB_DELAY, BOMB_DURATION,
    SNIPER_START_STEPS, SNIPER_MAX_STEPS, SNIPER_KILL_DELAY, SNIPER_FORWARD_RESET,
    DEATH_C4, DEATH_SNIPER,
} from '../Logic/constants';

export default function DangerController() {
    const world = useWorld();

    // ── БОМБА ──────────────────────────────────────────────────────────────────
    const bombStart     = useRef(null);
    const bombBeepRef   = useRef(null);
    const bombActiveRef = useRef(false);

    const resetBomb = (disarmed = false) => {
        bombStart.current = null;
        if (bombActiveRef.current) {
            bombActiveRef.current = false;
            useGameStore.getState().setBombProgress(0);
            if (disarmed) SoundManager.play('bombDisarm', false);
        }
        if (bombBeepRef.current) { clearTimeout(bombBeepRef.current); bombBeepRef.current = null; }
    };

    // Subscribe to frequently-changing fields without causing React re-renders
    useEffect(() => {
        const unsub = useGameStore.subscribe((s, prev) => {
            const pauseChanged = s.isDead !== prev.isDead || s.isPaused !== prev.isPaused || s.upgradeMenuOpen !== prev.upgradeMenuOpen;
            if (pauseChanged && (s.isDead || s.isPaused || s.upgradeMenuOpen)) {
                resetBomb();
                resetSniper();
                useGameStore.getState().setSniperProgress(0);
            }
            if (s.isMoving !== prev.isMoving) {
                if (s.isMoving || s.isDead || s.isPaused || s.upgradeMenuOpen) resetBomb(s.isMoving);
                else bombStart.current = performance.now() / 1000;
            }
            if (s.forwardSteps !== prev.forwardSteps && sniperPosRef.current) {
                if (s.forwardSteps >= SNIPER_FORWARD_RESET) {
                    resetSniper();
                } else if (s.forwardSteps > 0 && !goingForward.current && !zoomOutPlayed.current) {
                    SoundManager.play('sniperZoomOut', false);
                    zoomOutPlayed.current = true;
                    goingForward.current = true;
                } else if (s.forwardSteps > 0) {
                    goingForward.current = true;
                }
            }
            if (s.backSteps !== prev.backSteps) {
                const steps = s.backSteps;
                if (steps === 0) { goingForward.current = true; return; }
                goingForward.current = false;
                if (steps === SNIPER_START_STEPS && !sniperPosRef.current) {
                    const player = world.playerRef?.current;
                    if (player) {
                        const side = Math.random() > 0.5 ? 1 : -1;
                        const rx = side * (10 + Math.random() * 8);
                        const rz = -(8 + Math.random() * 6);
                        sniperPosRef.current = { x: player.position.x + rx, z: player.position.z + rz };
                    }
                }
                if (sniperPosRef.current) {
                    const p = Math.min((steps - SNIPER_START_STEPS) / (SNIPER_MAX_STEPS - SNIPER_START_STEPS), 0.9);
                    useGameStore.getState().setSniperProgress(p);
                }
            }
        });
        return unsub;
    }, []); // eslint-disable-line react-hooks/exhaustive-deps

    // ── СНАЙПЕР ────────────────────────────────────────────────────────────────
    const sniperPosRef   = useRef(null);  // { x, z } — текущая позиция прицела
    const sniperLockedRef = useRef(false); // true когда progress=1, ждём delay
    const sniperLockTime  = useRef(null);  // момент когда достигли progress=1
    const sniperFiredRef  = useRef(false);
    const goingForward    = useRef(false);
    const zoomOutPlayed   = useRef(false);

    const resetSniper = () => {
        sniperPosRef.current  = null;
        sniperLockedRef.current = false;
        sniperLockTime.current  = null;
        sniperFiredRef.current  = false;
        goingForward.current    = false;
        zoomOutPlayed.current   = false;
        useGameStore.getState().setSniperProgress(0);
    };


    useFrame(() => {
        const { isDead: dead, isPaused: paused, upgradeMenuOpen: upgradeOpen,
                isStarted, isInvulnerable, isMoving,
                die, setBombProgress, setSniperProgress } = useGameStore.getState();
        if (dead || paused || upgradeOpen || !isStarted || isInvulnerable) return;
        const player = world.playerRef?.current;
        if (!player) return;
        const now = performance.now() / 1000;

        // ── БОМБА тик ──────────────────────────────────────────────────────────
        if (!isMoving && bombStart.current !== null) {
            const idleTime = now - bombStart.current;
            if (idleTime >= BOMB_DELAY) {
                const progress = Math.min((idleTime - BOMB_DELAY) / BOMB_DURATION, 1);
                if (!bombActiveRef.current) {
                    bombActiveRef.current = true;
                    SoundManager.play('bombInitiate', false);
                    const startBeeping = () => {
                        if (!bombActiveRef.current) return;
                        SoundManager.play('bombBeep', false);
                        const elapsed = (performance.now() / 1000) - bombStart.current - BOMB_DELAY;
                        bombBeepRef.current = setTimeout(startBeeping, Math.max(100, 800 - elapsed * 95));
                    };
                    bombBeepRef.current = setTimeout(startBeeping, 400);
                }
                setBombProgress(progress);
                if (progress >= 1) {
                    resetBomb();
                    die(DEATH_C4, [player.position.x, 0.5, player.position.z]);
                }
            }
        }

        // ── СНАЙПЕР: движение прицела ──────────────────────────────────────────
        if (!sniperPosRef.current || sniperFiredRef.current) return;
        const sc = sniperPosRef.current;
        const steps = useGameStore.getState().backSteps;

        if (goingForward.current) {
            // Медленный дрейф назад и в сторону
            sc.z -= 0.035;
            sc.x += (player.position.x - sc.x) * 0.008;
            // Уходит слишком далеко — сбрасываем
            if (player.position.z - sc.z > 14) {
                resetSniper();
                return;
            }
            // Прогресс чуть снижается
            const cur = useGameStore.getState().sniperProgress;
            setSniperProgress(Math.max(0, cur - 0.012));
        } else {
            // Очень медленное наведение — нарастает с каждым шагом назад
            const speed = Math.min(0.002 + (steps - SNIPER_START_STEPS) * 0.008, 0.04);
            sc.x += (player.position.x - sc.x) * speed;
            sc.z += (player.position.z - sc.z) * speed;

            // Измеряем дистанцию до игрока
            const dx = sc.x - player.position.x;
            const dz = sc.z - player.position.z;
            const dist = Math.sqrt(dx * dx + dz * dz);

            if (dist < 0.25 && !sniperLockedRef.current) {
                // Навелись — ждём SNIPER_KILL_DELAY
                sniperLockedRef.current = true;
                sniperLockTime.current  = now;
                setSniperProgress(1.0);
            }

            if (sniperLockedRef.current) {
                const waited = now - sniperLockTime.current;
                // Прицел дрожит на игроке
                sc.x = player.position.x + Math.sin(now * 18) * 0.04;
                sc.z = player.position.z + Math.cos(now * 14) * 0.04;

                if (waited >= SNIPER_KILL_DELAY && !sniperFiredRef.current) {
                    sniperFiredRef.current = true;
                    setSniperProgress(0);
                    SoundManager.play('sniperShot', false);
                    die(DEATH_SNIPER, [player.position.x, 0.5, player.position.z]);
                    return;
                }
            }
        }

    });

    return null;
}
