import { OrthographicCamera, PerspectiveCamera } from "@react-three/drei";
import { useFrame, useThree } from "@react-three/fiber";
import { useRef, useState, useEffect } from "react";
import * as THREE from 'three';
import { useWorld } from "../Logic/GameWorldContext";
import { useGameStore } from "../Logic/store";
import { SoundManager } from "../Effects/SoundManager";
import gsap from "gsap";
import {
    CAMERA_BASE_ZOOM, CAMERA_MOBILE_DIV, CAMERA_MOBILE_MUL, CAMERA_MOBILE_MIN_ZOOM,
    CAMERA_OFFSET, CAMERA_HEIGHT, CAMERA_FAR, CAMERA_NEAR,
    CAMERA_DESKTOP_SCALE_X, CAMERA_DESKTOP_DELTA_Z,
    CAMERA_MOBILE_SCALE_X, CAMERA_MOBILE_DELTA_Z,
    CAMERA_SNIPER_ZOOM_MUL, CAMERA_SNIPER_SCALE_X, CAMERA_SNIPER_DELTA_Z,
    CAMERA_LERP_ZOOM, CAMERA_LERP_POS, CAMERA_LERP_LOOK,
    CAMERA_MENU_POS, CAMERA_MENU_FOV, CAMERA_MENU_LOOK,
    CAMERA_MENU_LERP, CAMERA_START_DURATION,
} from "../Logic/constants";

export default function SmartCamera() {
  const { size } = useThree();
  const cameraRef = useRef(); // orthographic — game camera
  const perspRef  = useRef(); // perspective — menu camera
  const world     = useWorld();

  const isMobile   = size.width < size.height;
  const mobileZoom = (size.width / CAMERA_MOBILE_DIV) * CAMERA_MOBILE_MUL;
  const zoom       = isMobile ? Math.max(mobileZoom, CAMERA_MOBILE_MIN_ZOOM) : CAMERA_BASE_ZOOM;

  const lookTarget  = useRef(new THREE.Vector3(...CAMERA_MENU_LOOK));
  const idealPos    = useRef(new THREE.Vector3());
  const playerFloor = useRef(new THREE.Vector3());
  const offset      = useRef(new THREE.Vector3(...CAMERA_OFFSET));

  const baseScaleX = isMobile ? CAMERA_MOBILE_SCALE_X : CAMERA_DESKTOP_SCALE_X;
  const baseDeltaZ = isMobile ? CAMERA_MOBILE_DELTA_Z : CAMERA_DESKTOP_DELTA_Z;

  const currentScaleX = useRef(baseScaleX);
  const currentDeltaZ = useRef(baseDeltaZ);

  const targetZoom = useRef(zoom);
  const sniperWas  = useRef(false);

  // ── Menu / transition state ────────────────────────────────────────────────
  const menuMode           = useRef(true);   // true = perspective menu mode
  const menuAnimating      = useRef(false);  // GSAP transition in progress
  const waitingForPlayerY  = useRef(false);  // waiting for chicken Y ≥ 0 before fly-in
  const flyInStarted       = useRef(false);  // GSAP fly-in launched (guard)
  const menuReturn         = useRef(false);  // true = returning to lobby
  const orthoReturnActive  = useRef(false);  // true = Phase 0: ortho sliding back to start
  const menuCamPos         = useRef(new THREE.Vector3(...CAMERA_MENU_POS));
  const menuLookPt         = useRef(new THREE.Vector3(...CAMERA_MENU_LOOK));
  // Fixed camera→lookAt offset, used to track chicken during intro wait
  const menuCamOffset      = new THREE.Vector3(...CAMERA_MENU_POS).sub(new THREE.Vector3(...CAMERA_MENU_LOOK));
  const introCamScale      = useRef({ value: 1.0 }); // animated 1→0.6 on intro start
  const introOrthoActive   = useRef(false);           // lookAt lerps to [0,0] while chicken walks in
  const phase0Active       = useRef(false);           // Phase 0: ortho-angle close-up while chicken walks in
  const phase2Pending      = useRef(false);           // Phase 1 done → fire Phase 2 next frame
  // Direction from lookAt to camera in game ortho mode (normalized CAMERA_OFFSET)
  const orthoDir           = new THREE.Vector3(...CAMERA_OFFSET).normalize();
  const sizeRef            = useRef(size);
  const [isPersp, setIsPersp] = useState(true);

  sizeRef.current = size;

  // ── Inverse transition: ortho game camera → perspective menu camera ────────
  useEffect(() => {
    const unsub = useGameStore.subscribe((state, prev) => {
      if (state.isStarted || state.isStarted === prev.isStarted) return;

      gsap.killTweensOf(perspRef.current?.position);
      gsap.killTweensOf(perspRef.current);
      gsap.killTweensOf(cameraRef.current?.position);
      gsap.killTweensOf(cameraRef.current);
      gsap.killTweensOf(targetZoom);
      gsap.killTweensOf(currentScaleX);
      gsap.killTweensOf(currentDeltaZ);

      const persp = perspRef.current;
      const ortho = cameraRef.current;

      // Fallback: instant snap if cameras not ready yet (early load)
      if (!persp || !ortho) {
        menuMode.current      = true;
        menuAnimating.current = false;
        menuReturn.current    = false;
        orthoReturnActive.current = false;
        if (persp) {
          persp.position.set(...CAMERA_MENU_POS);
          persp.fov = CAMERA_MENU_FOV; persp.near = CAMERA_NEAR; persp.far = CAMERA_FAR;
          persp.updateProjectionMatrix();
        }
        lookTarget.current.copy(menuLookPt.current);
        setIsPersp(true);
        return;
      }

      // ── Phase 0: ortho stays active, slides smoothly back to start ────────
      const off     = offset.current;
      const startP  = new THREE.Vector3(off.x, CAMERA_HEIGHT, off.z);
      const dist    = ortho.position.distanceTo(startP);
      const phase0dur = Math.min(1.2, Math.max(0.35, dist * 0.008));

      menuMode.current          = false;
      menuAnimating.current     = true;
      menuReturn.current        = true;
      orthoReturnActive.current = true;
      // isPersp stays false — ortho remains makeDefault during Phase 0

      gsap.to(ortho.position, {
        x: startP.x, y: startP.y, z: startP.z,
        duration: phase0dur, ease: 'power2.inOut',
        onComplete: () => {
          orthoReturnActive.current = false;

          // ── Phase 1 setup: match persp to ortho at fov≈0 ────────────────
          const k      = (sizeRef.current.height / 2) / ortho.zoom;
          const fov0   = 0.5;
          const lookPt = lookTarget.current.clone();
          const viewDir = new THREE.Vector3().subVectors(ortho.position, lookPt).normalize();
          const dist0  = k / Math.tan((fov0 / 2) * (Math.PI / 180));

          persp.position.copy(lookPt).addScaledVector(viewDir, dist0);
          persp.fov  = fov0;
          persp.near = Math.min(dist0 * 0.1, 10);
          persp.far  = dist0 * 5;
          persp.updateProjectionMatrix();

          setIsPersp(true); // switch makeDefault: ortho → persp

          // ── Phase 1 (0.6 s): widen fov 0.5° → 13°, maintain frustum k ──
          gsap.to(persp, {
            fov: 13, duration: 0.6, ease: 'power2.out',
            onUpdate: () => {
              const d = k / Math.tan((persp.fov / 2) * (Math.PI / 180));
              persp.position.copy(lookPt).addScaledVector(viewDir, d);
              persp.near = Math.min(d * 0.1, 10);
              persp.far  = d * 5;
              persp.updateProjectionMatrix();
            },
            onComplete: () => {
              // ── Phase 2: fly to menu, widen fov 13° → 20° ───────────────
              gsap.to(persp, {
                fov: CAMERA_MENU_FOV, duration: CAMERA_START_DURATION, ease: 'power2.inOut',
              });
              gsap.to(persp.position, {
                x: CAMERA_MENU_POS[0], y: CAMERA_MENU_POS[1], z: CAMERA_MENU_POS[2],
                duration: CAMERA_START_DURATION, ease: 'power2.inOut',
                onComplete: () => {
                  persp.near = CAMERA_NEAR;
                  persp.far  = CAMERA_FAR;
                  persp.updateProjectionMatrix();
                  menuMode.current          = true;
                  menuAnimating.current     = false;
                  menuReturn.current        = false;
                  waitingForPlayerY.current = false;
                  flyInStarted.current      = false;
                  phase0Active.current      = false;
                },
              });
            },
          });
        },
      });
    });

    return () => {
      unsub();
      gsap.killTweensOf(perspRef.current);
      gsap.killTweensOf(cameraRef.current);
      gsap.killTweensOf(targetZoom);
      gsap.killTweensOf(currentScaleX);
      gsap.killTweensOf(currentDeltaZ);
    };
  }, []);

  useFrame(() => {
    const player = world.playerRef?.current;
    if (!player) return;

    const { isStarted, sniperActive, isIntroPlaying } = useGameStore.getState();

    // ── Trigger game-start fly-in (once) ──────────────────────────────────
    // Step 1: isStarted → stop menu lerp, wait for chicken Y to change
    if (isStarted && menuMode.current && !menuAnimating.current && perspRef.current) {
      menuMode.current          = false;
      waitingForPlayerY.current = true;
      flyInStarted.current      = false;
      introCamScale.current.value = 1.0;
      gsap.to(introCamScale.current, { value: 0.6, duration: 2.5, ease: 'power2.inOut' });
    }

    // Step 2: menu-angle follow until Y first changes → switch to Phase 0
    if (waitingForPlayerY.current) {
      if (perspRef.current) {
        playerFloor.current.set(player.position.x, -1.75, player.position.z);
        lookTarget.current.lerp(playerFloor.current, 0.03);
        idealPos.current.copy(lookTarget.current).addScaledVector(menuCamOffset, introCamScale.current.value);
        perspRef.current.position.lerp(idealPos.current, 0.03);
        perspRef.current.lookAt(lookTarget.current);
      }
      if (player.position.y > -1.7) {
        waitingForPlayerY.current = false;
        menuAnimating.current     = true;
        phase0Active.current      = true;
      } else {
        return;
      }
    }

    // ── Menu mode: hold perspective camera at frontal position ────────────
    if (menuMode.current) {
      if (!perspRef.current) return;
      perspRef.current.position.lerp(menuCamPos.current, CAMERA_MENU_LERP);
      lookTarget.current.lerp(menuLookPt.current, CAMERA_MENU_LERP);
      perspRef.current.lookAt(lookTarget.current);
      return;
    }

    // ── Phase 2: fire immediately when Phase 1 GSAP is done ──────────────
    if (phase2Pending.current && perspRef.current) {
      phase2Pending.current = false;
      // Compute fresh from current state so player movement during Phase 1 is handled
      const lookPt  = lookTarget.current.clone();
      const dist0   = perspRef.current.position.distanceTo(lookPt);
      const k       = dist0 * Math.tan((perspRef.current.fov / 2) * (Math.PI / 180));
      const viewDir = new THREE.Vector3().subVectors(perspRef.current.position, lookPt).normalize();
      gsap.to(perspRef.current, {
        fov: 0.5,
        duration: 0.6,
        ease: 'power2.in',
        onUpdate: () => {
          if (!perspRef.current) return;
          const newDist = k / Math.tan((perspRef.current.fov / 2) * (Math.PI / 180));
          perspRef.current.position.copy(lookPt).addScaledVector(viewDir, newDist);
          perspRef.current.near = Math.min(newDist * 0.1, 10);
          perspRef.current.far  = newDist * 5;
          perspRef.current.updateProjectionMatrix();
        },
        onComplete: () => {
          if (!cameraRef.current || !perspRef.current) return;
          const matchZoom = (size.height / 2) / k;
          cameraRef.current.position.copy(perspRef.current.position);
          cameraRef.current.lookAt(lookPt);
          cameraRef.current.zoom = matchZoom;
          cameraRef.current.updateProjectionMatrix();
          targetZoom.current = matchZoom;
          gsap.to(targetZoom, { current: zoom, duration: 0.5, ease: 'power2.inOut' });
          menuAnimating.current    = false;
          introOrthoActive.current = true;
          useGameStore.setState({ isIntroPlaying: false });
          setIsPersp(false);
        },
      });
    }

    // ── Transition: GSAP drives cameras; lerp lookAt ──────────────────────
    if (menuAnimating.current) {
      if (orthoReturnActive.current) {
        // Phase 0: ortho slides to start — update its lookAt each frame
        lookTarget.current.lerp(menuLookPt.current, 0.04);
        if (cameraRef.current) cameraRef.current.lookAt(lookTarget.current);
        return;
      }
      // Persp active
      if (!perspRef.current) return;
      perspRef.current.updateProjectionMatrix();
      if (menuReturn.current) {
        lookTarget.current.lerp(menuLookPt.current, 0.03);
        perspRef.current.lookAt(lookTarget.current);
      } else if (phase0Active.current) {
        // ── Phase 0: ortho angle, close to chicken, follow it ─────────────
        const pPos2 = player.position;
        playerFloor.current.set(pPos2.x, 0, pPos2.z);
        lookTarget.current.lerp(playerFloor.current, 0.05);
        // Camera at game-ortho direction but close (40% of full offset distance)
        idealPos.current.copy(lookTarget.current).addScaledVector(orthoDir, offset.current.length() * 0.4);
        perspRef.current.position.lerp(idealPos.current, 0.03);
        perspRef.current.lookAt(lookTarget.current);

        // Immediately launch Phase 1 fly-in targeting [0,0,0]
        if (!flyInStarted.current) {
          phase0Active.current = false;
          flyInStarted.current = true;
          const gameX = offset.current.x;
          const gameZ = offset.current.z;
          gsap.to(perspRef.current, { fov: 13, duration: CAMERA_START_DURATION, ease: 'power2.inOut' });
          gsap.to(perspRef.current.position, {
            x: gameX, y: CAMERA_HEIGHT, z: gameZ,
            duration: CAMERA_START_DURATION, ease: 'power2.inOut',
            onComplete: () => {
              phase2Pending.current = true;
            },
          });
        }
      } else {
        // ── Phase 1 in progress: GSAP drives position; lookAt follows player ─
        playerFloor.current.set(
          currentScaleX.current * player.position.x,
          0,
          player.position.z + currentDeltaZ.current
        );
        lookTarget.current.lerp(playerFloor.current, CAMERA_LERP_LOOK);
        perspRef.current.lookAt(lookTarget.current);
      }
      return;
    }

    if (!cameraRef.current) return;

    // ── Normal orthographic game follow ───────────────────────────────────
    if (sniperActive && !sniperWas.current) {
      sniperWas.current = true;
      SoundManager.play('sniperZoom', false);
      gsap.to(targetZoom, { current: zoom * CAMERA_SNIPER_ZOOM_MUL, duration: 0.65, ease: 'power2.out' });
      gsap.to(currentScaleX, { current: CAMERA_SNIPER_SCALE_X, duration: 0.65, ease: 'power2.out' });
      gsap.to(currentDeltaZ, { current: CAMERA_SNIPER_DELTA_Z, duration: 0.65, ease: 'power2.out' });
    } else if (!sniperActive && sniperWas.current) {
      sniperWas.current = false;
      gsap.to(targetZoom, { current: zoom, duration: 0.55, ease: 'power2.inOut' });
      gsap.to(currentScaleX, { current: baseScaleX, duration: 0.55, ease: 'power2.inOut' });
      gsap.to(currentDeltaZ, { current: baseDeltaZ, duration: 0.55, ease: 'power2.inOut' });
    }

    const zoomDelta = (targetZoom.current - cameraRef.current.zoom) * CAMERA_LERP_ZOOM;
    if (Math.abs(zoomDelta) > 0.001) {
        cameraRef.current.zoom += zoomDelta;
        cameraRef.current.updateProjectionMatrix();
    }

    const pPos    = player.position;
    const scaledX = currentScaleX.current * pPos.x;
    const off     = offset.current;

    idealPos.current.set(scaledX + off.x, CAMERA_HEIGHT, pPos.z + off.z);
    cameraRef.current.position.lerp(idealPos.current, CAMERA_LERP_POS);

    // During intro: lookAt lerps to [0,0] regardless of chicken's current hop position
    if (introOrthoActive.current) {
      playerFloor.current.set(0, 0, currentDeltaZ.current);
      if (Math.abs(pPos.x) < 0.2 && Math.abs(pPos.z) < 0.2) introOrthoActive.current = false;
    } else {
      playerFloor.current.set(scaledX, 0, pPos.z + currentDeltaZ.current);
    }
    lookTarget.current.lerp(playerFloor.current, CAMERA_LERP_LOOK * 1.6);
    cameraRef.current.lookAt(lookTarget.current);
  });

  return (
    <>
      <PerspectiveCamera
        ref={ perspRef }
        makeDefault={ isPersp }
        fov={ CAMERA_MENU_FOV }
        position={ CAMERA_MENU_POS }
        near={ CAMERA_NEAR }
        far={ CAMERA_FAR }
      />
      <OrthographicCamera
        ref={ cameraRef }
        makeDefault={ !isPersp }
        zoom={ zoom }
        position={ CAMERA_MENU_POS }
        far={ CAMERA_FAR }
        near={ CAMERA_NEAR }
      />
    </>
  );
}
