import { useRef, useState, useEffect } from 'react';
import { useGameStore } from '../Logic/store';
import { F_UI, F_TITLE, OG_GRAD, C_BTN_SHADOW } from './uiTheme';
import { GameCard, GameButton, useScrollThumb, ScrollTrack, ScreenFade } from './GameCard';
import { useT } from './i18n';


function prizeForRank(rank, t) {
    if (rank === -1)             return { weapon: 'NA',          skin: '',               tier: ''       };
    if (rank === 1)              return { weapon: 'Nomad Knife', skin: 'Tiger Tooth',    tier: 'gold'   };
    if (rank === 2)              return { weapon: 'M4A1-S',      skin: 'Vaporwave',      tier: 'silver' };
    if (rank >= 3  && rank <= 5) return { weapon: 'AWP',         skin: 'Hyper Beast',    tier: 'bronze' };
    if (rank >= 6  && rank <= 10)return { weapon: 'AK-47',       skin: 'Frontside Misty',tier: 'base'   };
    if (rank >= 11 && rank <= 15)return { weapon: t.promoWeapon, skin: t.promoSkin,      tier: 'promo'  };
    return null;
}

const MOCK_LEADERBOARD = Array.from({ length: 15 }, (_, i) => ({
    rank: i + 1,
    email: 'example@gmail.com',
    score: '99.999',
}));

function PrizeBadge({ rank }) {
    const t = useT();
    const p = prizeForRank(rank, t);
    if (!p) return null;
    return (
        <div style={{
            display: 'flex', flexDirection: 'column', alignItems: 'center',
            gap: 1, flexShrink: 0,
        }}>
            <div style={{
                fontFamily: F_UI, fontSize: 10, fontWeight: 700,
                color: '#fff', lineHeight: 1.1, letterSpacing: '4%',
                whiteSpace: 'pre-line', textAlign: 'center', textShadow: `0 2px 0px #181A27`,
            }}>{`${p.weapon}\n${p.skin}`}</div>
        </div>
    );
}

