import { useRef } from 'react';
import { useGameStore } from '../Logic/store';
import { F_UI, F_TITLE, GRADIENT_MASK, OG_GRAD } from './uiTheme';
import { GameCard, ScreenFade, useScrollThumb, ScrollTrack } from './GameCard';
import { useT } from './i18n';

const PRIZE_WEAPONS = [
    { weapon: 'Nomad Knife', skin: 'Tiger Tooth',     tier: 'gold'   },
    { weapon: 'M4A1-S',      skin: 'Vaporwave',       tier: 'silver' },
    { weapon: 'AWP',          skin: 'Hyper Beast',     tier: 'bronze' },
    { weapon: 'AK-47',        skin: 'Frontside Misty', tier: 'base'   },
    { weapon: null,           skin: null,               tier: 'promo'  },
];

const ITEM_BG = '#494D5E';


function PrizeRow({ place, weapon, skin, position }) {
    return (
        <div style={{ position: 'relative', flexShrink: 0 }}>
            {/* Shadow */}
            <div style={{
                position: 'absolute',
                left: 0, right: 0, top: 4, bottom: -8,
                background: '#181A27',
                borderRadius: 8,
                boxShadow: '0 4px 1px #00000060',
            }} />

            <div style={{
                position: 'relative',
                display: 'flex', alignItems: 'center',
                height: 78,
                padding: '0 12px', gap: 12,
                background: ITEM_BG,
                borderRadius: 8,
                boxShadow: `inset 0 0 0 2px rgba(255,255,255,0.1)`,
            }}>
                {/* Image backing card */}
                <div style={{
                    boxSizing: 'border-box',
                    position: 'absolute',
                    width: 112, height: 86,
                    background: 'linear-gradient(180deg, #FFB60C 60%, #FF931F 100%)',
                    borderRadius: 12,
                    filter: 'drop-shadow(0 4px 0 #181A27)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                } }>
                    {/* Stroke 4 inside */ }
                <div style={{
                    zIndex: 0,
                    position: 'absolute', inset: 0,
                    borderRadius: 12,
                    boxSizing: 'border-box',
                    border: '2px solid transparent',
                    backgroundImage: 'linear-gradient(#ffffff, #ffffff), linear-gradient(to bottom, transparent 0%, #ffffff63 100%)',
                    backgroundOrigin: 'border-box',
                    backgroundClip: 'padding-box, border-box',
                    ...GRADIENT_MASK,
                    pointerEvents: 'none',
                    zIndex: 2,
                }} />
                    <img
                        src={`/images/Prize${position}.webp`}
                        alt=""
                        style={{ width: '90%', height: '90%', objectFit: 'contain', filter: 'drop-shadow(-2px 2px 0 rgba(0,0,0,0.45))' }}
                    />
                </div>
            
                {/* Text */}
                <div style={{ marginLeft: 120, flex: 1, minWidth: 0, display: 'flex', flexDirection: 'column', gap: 4, justifyContent: 'center' }}>
                    <div style={{
                        fontFamily: F_TITLE, fontSize: 'clamp(20px, 3.8vw, 20px)', fontWeight: 700,
                        background: OG_GRAD,
                        WebkitBackgroundClip: 'text', backgroundClip: 'text',
                        WebkitTextFillColor: 'transparent',
                        filter: 'drop-shadow(0 3px 0 #000000)',
                        whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
                    }}>{place}</div>
                    <div style={{
                        fontFamily: F_UI, fontSize: 'clamp(10px, 2.8vw, 12px)', fontWeight: 700,
                        color: '#fff', letterSpacing: '4%', lineHeight: 1.1,
                        whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
                        textShadow: '0 2px 0 #181A27',
                    }}>{weapon} | {skin}</div>
                </div>
            </div>
        </div>
    );
}

export default function PrizeMenu() {
    const t = useT();
    const isChestOpen   = useGameStore(s => s.isChestOpen);
    const closeChestAll = useGameStore(s => s.closeChestAll);
    const scrollRef = useRef(null);
    const { thumb } = useScrollThumb(scrollRef, isChestOpen);

    const PRIZES = PRIZE_WEAPONS.map((p, i) => ({
        place:  t.places[i],
        weapon: p.tier === 'promo' ? t.promoWeapon : p.weapon,
        skin:   p.tier === 'promo' ? t.promoSkin   : p.skin,
        tier:   p.tier,
    }));

    if (!isChestOpen) return null;

    return (
        <div
            onPointerDown={closeChestAll}
            style={{
                position: 'fixed', inset: 0, zIndex: 2200,
                background: 'rgba(10,5,20,0.72)',
                backdropFilter: 'blur(10px)',
                WebkitBackdropFilter: 'blur(10px)',
                display: 'flex', flexDirection: 'column', alignItems: 'center',
                paddingTop: 'max(env(safe-area-inset-top, 0px), 16px)',
                paddingBottom: 'calc(96px + env(safe-area-inset-bottom, 0px))',
                paddingLeft: 18, paddingRight: 18,
                gap: 12,
            }}>
            <ScreenFade />

           {/* Заголовок */}
            <div
                onPointerDown={ e => e.stopPropagation() }
                style={ {
                    width: '100%', maxWidth: 420,
                    zIndex: 1,
                    color: '#ffffff00',
                    borderRadius: 12,
                    padding: '46px 20px 12px',
                    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 32,
                    flex: 1, minHeight: 0,
                }}
            >
                <GameCard
                    zIndex={ 20 }
                    wrapperStyle={{ position: 'relative', width: '90%' }}
                    onPointerDown={e => e.stopPropagation()}
                    style={ {
                        zIndex: 20,
                        padding: '4px 4px 4px',
                        height: '48px',
                        display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'center', gap: '12px',
                    }}
                >
                <div style={{
                    fontFamily: F_TITLE,
                    textAlign: 'center',
                    fontSize: 'clamp(20px, 5vw, 20px)',
                    fontWeight: 700, color: '#fff', letterSpacing: '2%',
                    textShadow: '0 4px 0px #181A27',
                }}>{t.prizesTitle}</div>
            </GameCard>

            {/* Список */}
            <GameCard
                zIndex={ 1 }
                wrapperStyle={{ position: 'relative', marginTop: -36, flex: 1, minHeight: 0, maxHeight: 590, display: 'flex', flexDirection: 'column' }}
                onPointerDown={e => e.stopPropagation()}
                style={{
                    flex: 1, minHeight: 0,
                    display: 'flex', flexDirection: 'column',
                    overflow: 'hidden',
                }}
             >
                    {/* padding сверху под заголовок */}
                    <div style={{ height: 32, flexShrink: 0 }} />

                    <div ref={scrollRef} style={{
                        flex: 1, minHeight: 0,
                        overflowY: 'auto', scrollbarWidth: 'none',
                        WebkitOverflowScrolling: 'touch',
                        touchAction: 'pan-y',
                        padding: '0 28px 16px 12px',
                        display: 'flex', flexDirection: 'column', gap: 24,
                    }}>
                        {PRIZES.map((p, i) => (
                            <PrizeRow key={i} {...p} position={i + 1} />
                        ))}
                    </div>
                    <ScrollTrack ratio={thumb.ratio} thumbH={thumb.h} visible={thumb.visible} topOffset={32} />
                </GameCard>
            </div>
        </div>
    );
}
