import * as THREE from 'three';
import gsap from 'gsap';
import { forwardRef, useImperativeHandle, useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';

const FIRE_COUNT = 10;
const INSTANCES  = FIRE_COUNT * 2; // plane-A + plane-B per fire
const RADIUS     = 1.3;
const DURATION   = 5.0;

const _dummy = new THREE.Object3D();

// ── Shaders ────────────────────────────────────────────────────────────────────
const vertexShader = /* glsl */`
// instanceMatrix is auto-declared by Three.js prefix when USE_INSTANCING is defined
attribute float aSeed;
uniform  float  uTime;
varying  vec2   vUv;
varying  float  vSeed;

void main() {
    vUv   = uv;
    vSeed = aSeed;
    vec3  pos = position;
    float h   = uv.y * uv.y;
    float spd = 2.1 + aSeed * 0.7;
    pos.x += sin(uTime * spd        + position.y * 3.2) * h * 0.11;
    pos.z += cos(uTime * (spd-0.5)  + position.y * 2.9) * h * 0.08;
    gl_Position = projectionMatrix * modelViewMatrix * instanceMatrix * vec4(pos, 1.0);
}
`;

const fragmentShader = /* glsl */`
uniform float uTime;
uniform float uStartTime;
uniform float uOpacity;
varying vec2  vUv;
varying float vSeed;

float hash(vec2 p) {
    p = fract(p * vec2(234.34, 435.346));
    p += dot(p, p + 34.23);
    return fract(p.x * p.y);
}
float noise(vec2 p) {
    vec2 i = floor(p), f = fract(p);
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(mix(hash(i),          hash(i + vec2(1.0, 0.0)), u.x),
               mix(hash(i+vec2(0,1)), hash(i + vec2(1.0, 1.0)), u.x), u.y);
}
float fbm(vec2 p) {
    return noise(p)              * 0.50
         + noise(p * 2.1 + 5.3)  * 0.32
         + noise(p * 4.3 + 11.5) * 0.18;
}

void main() {
    // Staggered per-instance spawn — no extra attribute needed, derived from seed
    float elapsed   = uTime - uStartTime;
    float spawnAt   = mod(vSeed * 3.7, 1.0) * 0.65;   // 0..0.65 s delay
    float spawnFade = smoothstep(0.0, 0.35, elapsed - spawnAt);

    vec2  uv = vUv;
    float t  = uTime + vSeed;
    uv.y -= t * 0.72;
    uv.x += sin(t * 0.45 + vUv.y * 3.2) * 0.065;

    float n    = fbm(uv * vec2(3.2, 2.5));
    float sx   = pow(1.0 - abs(vUv.x * 2.0 - 1.0), 0.55);
    float sy   = pow(1.0 - vUv.y, 0.38);
    float fire = smoothstep(0.26, 0.72, n * sx * sy * 1.55);

    if (fire < 0.01) discard;

    float pulse = 0.78 + 0.22 * sin(uTime * 2.2 + vSeed * 5.4);

    vec3 c = vec3(0.9, 0.08, 0.0);
    c = mix(c, vec3(1.0, 0.48, 0.0),  smoothstep(0.0,  0.38, fire));
    c = mix(c, vec3(1.0, 0.86, 0.10), smoothstep(0.38, 0.68, fire));
    c = mix(c, vec3(1.0, 1.0,  0.82), smoothstep(0.68, 1.0,  fire));

    gl_FragColor = vec4(c, fire * uOpacity * pulse * spawnFade);
}
`;

// ── Component ─────────────────────────────────────────────────────────────────
const FireFBM = forwardRef(function FireFBM(_, ref) {
    const meshRef  = useRef();
    const active   = useRef(false);
    const clockRef = useRef(null);
    const tween    = useRef(null);

    const uniforms = useRef({
        uTime:      { value: 0 },
        uStartTime: { value: 0 },
        uOpacity:   { value: 0 },
    });

    // Geometry with per-instance aSeed — created once, never recreated
    const geometry = useMemo(() => {
        const geo = new THREE.PlaneGeometry(0.7, 0.75, 1, 4);
        geo.translate(0, 0.375, 0); // base at y=0

        const seeds = new Float32Array(INSTANCES);
        for (let i = 0; i < FIRE_COUNT; i++) {
            seeds[i]              = i * 0.97;        // plane-A seeds
            seeds[i + FIRE_COUNT] = i * 0.97 + 1.73; // plane-B seeds (offset breaks symmetry)
        }
        geo.setAttribute('aSeed', new THREE.InstancedBufferAttribute(seeds, 1));
        return geo;
    }, []);

    useImperativeHandle(ref, () => ({
        start(x, z) {
            const mesh = meshRef.current;
            if (!mesh) return;

            // Move mesh to death position; instance matrices use local offsets
            mesh.position.set(x, 0, z);

            // Scatter 6 fire positions; each position gets two planes (A=45°, B=135°)
            for (let i = 0; i < FIRE_COUNT; i++) {
                const angle = Math.random() * Math.PI * 2;
                const r     = Math.random() * RADIUS;
                _dummy.position.set(Math.cos(angle) * r, 0, Math.sin(angle) * r);

                _dummy.rotation.set(0, Math.PI / 4, 0);
                _dummy.updateMatrix();
                mesh.setMatrixAt(i, _dummy.matrix);

                _dummy.rotation.set(0, Math.PI * 3 / 4, 0);
                _dummy.updateMatrix();
                mesh.setMatrixAt(i + FIRE_COUNT, _dummy.matrix);
            }
            mesh.instanceMatrix.needsUpdate = true;
            mesh.visible = true;
            active.current = true;

            const u = uniforms.current;
            u.uStartTime.value = clockRef.current?.elapsedTime ?? 0;
            u.uOpacity.value   = 1.0;

            if (tween.current) tween.current.kill();
            tween.current = gsap.to(u.uOpacity, {
                value: 0, duration: 1.5, ease: 'power2.in',
                delay: DURATION - 1.5,
                onComplete: () => { mesh.visible = false; active.current = false; },
            });
        },
        stop() {
            if (tween.current) tween.current.kill();
            if (meshRef.current) meshRef.current.visible = false;
            active.current = false;
            uniforms.current.uOpacity.value = 0;
        },
    }));

    useFrame(({ clock }) => {
        clockRef.current = clock;
        if (!active.current) return;
        uniforms.current.uTime.value = clock.elapsedTime;
    });

    return (
        <instancedMesh
            ref={meshRef}
            args={[geometry, null, INSTANCES]}
            visible={false}
            frustumCulled={false}
        >
            <shaderMaterial
                vertexShader={vertexShader}
                fragmentShader={fragmentShader}
                uniforms={uniforms.current}
                transparent
                depthWrite={false}
                side={THREE.DoubleSide}
            />
        </instancedMesh>
    );
});

export default FireFBM;
