import { useGLTF } from '@react-three/drei'
import { useFrame } from '@react-three/fiber'
import { useRef } from 'react'
import { sharedChickenMaterial } from '../View/sharedMaterial'


export default function Roasted({ material, visible, ...props }) {
    const { nodes } = useGLTF('/models/roasted.glb')
    const ref = useRef()

    useFrame((state) => {
        if (ref.current && visible) {
            ref.current.position.y = Math.max(0, Math.sin(state.clock.elapsedTime * 10) * 0.1)
        }
    })
    return (
        <group visible={visible} { ...props } dispose={ null }>
            <mesh
                geometry={ nodes.modelschickenchicken_roastedvmdl_cchicken_roasted004.geometry }
                material={ material ?? sharedChickenMaterial }
            />
        </group>
    )
}

useGLTF.preload('/models/roasted.glb')
