import * as THREE from 'three';
import gsap from 'gsap';
import { useEffect, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { useWorld } from '../Logic/GameWorldContext';

const POOL_SIZE = 3;
const DROPS    = 10;
const TOTAL    = POOL_SIZE * DROPS;

// Module-level shared resources — created once, never recreated
const _geo   = new THREE.SphereGeometry(0.065, 4, 4);
const _mat   = new THREE.MeshBasicMaterial({
    color: '#aaddff',
    transparent: true,
    opacity: 0.72,
    depthWrite: false,
});
const _dummy = new THREE.Object3D();

// Per-particle state — GSAP animates x/y/z/sx/sy/sz directly on these objects
const _state = Array.from({ length: TOTAL }, () => ({
    x: 0, y: -1000, z: 0,
    sx: 0.001, sy: 0.001, sz: 0.001,
}));

export default function WaterSplash() {
    const world       = useWorld();
    const meshRef     = useRef();
    const poolIdx     = useRef(0);
    const activeCount = useRef(0);

    useEffect(() => {
        // Park all instances off-screen
        const mesh = meshRef.current;
        if (mesh) {
            _dummy.position.set(0, -1000, 0);
            _dummy.scale.setScalar(0.001);
            _dummy.updateMatrix();
            for (let i = 0; i < TOTAL; i++) mesh.setMatrixAt(i, _dummy.matrix);
            mesh.instanceMatrix.needsUpdate = true;
        }

        world.emitWaterSplash = (x, z) => {
            const pi   = poolIdx.current % POOL_SIZE;
            poolIdx.current++;
            const base = pi * DROPS;
            activeCount.current += DROPS;

            for (let di = 0; di < DROPS; di++) {
                const p     = _state[base + di];
                const angle = Math.random() * Math.PI * 2;
                const r     = 0.08 + Math.random() * 0.5;
                const tx    = x + Math.cos(angle) * r;
                const tz    = z + Math.sin(angle) * r;
                const ty    = 0.05 + 0.4 + Math.random() * 1.0;
                const up    = 0.16 + Math.random() * 0.08;

                gsap.killTweensOf(p);

                p.x = x; p.y = 0.05; p.z = z;
                p.sx = 1; p.sy = 1; p.sz = 1;

                gsap.to(p, { x: tx, y: ty, z: tz, duration: up, ease: 'power2.out' });
                gsap.to(p, { y: -0.1, duration: 0.28, ease: 'power2.in', delay: up });
                gsap.to(p, {
                    sx: 0.001, sy: 0.001, sz: 0.001, duration: 0.25, delay: up * 0.6,
                    onComplete: () => { activeCount.current = Math.max(0, activeCount.current - 1); },
                });
            }
        };

        return () => { world.emitWaterSplash = null; };
    }, []); // eslint-disable-line

    useFrame(() => {
        if (activeCount.current <= 0) return;
        const mesh = meshRef.current;
        if (!mesh) return;
        for (let i = 0; i < TOTAL; i++) {
            const p = _state[i];
            _dummy.position.set(p.x, p.y, p.z);
            _dummy.scale.set(p.sx, p.sy, p.sz);
            _dummy.updateMatrix();
            mesh.setMatrixAt(i, _dummy.matrix);
        }
        mesh.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh
            ref={meshRef}
            args={[_geo, _mat, TOTAL]}
            frustumCulled={false}
        />
    );
}
