import { createContext, useContext } from "react";
import { gameState } from "./PhysicsEngine";

// Контекст, предоставляющий текущий игровой мир.
const GameWorldContext = createContext(gameState);

export function GameWorldProvider({ children }) {
  return (
    <GameWorldContext.Provider value={gameState}>
      {children}
    </GameWorldContext.Provider>
  );
}

export function useWorld() {
  const world = useContext(GameWorldContext);
  if (!world) {
    throw new Error("useWorld must be used within GameWorldProvider");
  }
  return world;
}

