import * as THREE from 'three';
import gsap from 'gsap';
import { useEffect, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { useWorld } from '../Logic/GameWorldContext';

const POOL_SIZE = 4;
const GRAINS   = 8;
const TOTAL    = POOL_SIZE * GRAINS;

// Module-level shared resources — created once, never recreated
const _geo   = new THREE.BoxGeometry(0.08, 0.05, 0.08);
const _mat   = new THREE.MeshBasicMaterial({
    color: '#c8a870',
    transparent: true,
    opacity: 0.65,
    depthWrite: false,
});
const _dummy = new THREE.Object3D();

// Per-particle state — GSAP animates x/y/z/sx/sy/sz directly on these objects
const _state = Array.from({ length: TOTAL }, () => ({
    x: 0, y: -1000, z: 0,
    sx: 0.001, sy: 0.001, sz: 0.001,
}));

export default function DustPuff() {
    const world        = useWorld();
    const meshRef      = useRef();
    const poolIdx      = useRef(0);
    const activeCount  = useRef(0);   // how many grains are currently animated

    useEffect(() => {
        // Park all instances off-screen
        const mesh = meshRef.current;
        if (mesh) {
            _dummy.position.set(0, -1000, 0);
            _dummy.scale.setScalar(0.001);
            _dummy.updateMatrix();
            for (let i = 0; i < TOTAL; i++) mesh.setMatrixAt(i, _dummy.matrix);
            mesh.instanceMatrix.needsUpdate = true;
        }

        world.emitDustPuff = (x, z) => {
            const pi   = poolIdx.current % POOL_SIZE;
            poolIdx.current++;
            const base = pi * GRAINS;
            activeCount.current += GRAINS;

            for (let di = 0; di < GRAINS; di++) {
                const p     = _state[base + di];
                const angle = Math.random() * Math.PI * 2;
                const r     = 0.15 + Math.random() * 0.55;
                const tx    = x + Math.cos(angle) * r;
                const tz    = z + Math.sin(angle) * r;
                const ty    = 0.05 + Math.random() * 0.25;
                const dur   = 0.18 + Math.random() * 0.1;

                gsap.killTweensOf(p);

                p.x = x; p.y = 0; p.z = z;
                p.sx = 1; p.sy = 1; p.sz = 1;

                gsap.to(p, { x: tx, y: ty, z: tz, duration: dur, ease: 'power2.out' });
                gsap.to(p, { y: 0, duration: 0.2, ease: 'power1.in', delay: dur });
                gsap.to(p, {
                    sx: 0.001, sy: 0.001, sz: 0.001, duration: 0.28, delay: dur * 0.5,
                    onComplete: () => { activeCount.current = Math.max(0, activeCount.current - 1); },
                });
            }
        };

        return () => { world.emitDustPuff = null; };
    }, []); // eslint-disable-line

    useFrame(() => {
        if (activeCount.current <= 0) return;
        const mesh = meshRef.current;
        if (!mesh) return;
        for (let i = 0; i < TOTAL; i++) {
            const p = _state[i];
            _dummy.position.set(p.x, p.y, p.z);
            _dummy.scale.set(p.sx, p.sy, p.sz);
            _dummy.updateMatrix();
            mesh.setMatrixAt(i, _dummy.matrix);
        }
        mesh.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh
            ref={meshRef}
            args={[_geo, _mat, TOTAL]}
            frustumCulled={false}
        />
    );
}
