// ── Special skin wrappers (must be rendered inside Canvas) ────────────────────
function FireSkinWrapper() {
    const { mat: chickenMat, uniforms: deformUniforms } = useMemo(() => createChickenDeformMaterial(), []);
    const { mat: fireMat, uniforms: fireUniforms } = useMemo(
        () => createFireSurfaceMaterial(deformUniforms), [deformUniforms]
    );
    useFrame(({ clock }) => { fireUniforms.uTime.value = clock.elapsedTime; });
    return (
        <ChickenSkin parts={[
            { names: ['chickenFire'],                          material: chickenMat },
            { names: ['chickenFireHead1', 'chickenFireHead2'], material: fireMat    },
        ]} />
    );
}

function GoldSkinWrapper() {
    const { mat: goldMat } = useMemo(() => createGoldDeformMaterial(), []);
    return (
        <ChickenSkin parts={[
            { names: ['chickenGold', 'chickenGoldDeagL', 'chickenGoldDeagR'], material: goldMat },
        ]} />
    );
}

// ── 3-D chicken (bobbing, no auto-rotate — OrbitControls handle that) ─────────
function PreviewChicken({ colorIdx, model, skinType, meshNames, overlayName }) {
    const groupRef = useRef();
    const { mat: chickenMat } = useMemo(() => createChickenDeformMaterial(), []);

    const { mat: auroraMat }  = useMemo(() => createAuroraDeformMaterial(),  []);
    useFrame((state) => {
        if (!groupRef.current) return;
        groupRef.current.position.y = Math.sin(state.clock.elapsedTime * 1.3) * 0.04 - 0.55;
    });
    return (
        <group ref={groupRef} scale={1.6}>
            {skinType === 'fire'   ? <FireSkinWrapper />
             : skinType === 'gold'   ? <GoldSkinWrapper />
             : skinType === 'atlas'  ? <ChickenSkin modelName={model} material={chickenMat} />
             : skinType === 'multi'  ? <ChickenSkin parts={meshNames.map(n => ({ names: [n], material: chickenMat }))} />
             : skinType === 'aurora' ? <ChickenSkin parts={[
                 { names: ['chickenAurora'], material: chickenMat },
                 { names: [overlayName],     material: auroraMat  },
               ]} />
             : model                 ? <ChickenSkin modelName={model} material={chickenMat} />
             :                         <Chicken colorIdx={colorIdx} material={chickenMat} />
            }
        </group>
    );
}

// ── Main component ────────────────────────────────────────────────────────────
export default function WardrobeMenu() {
    const t = useT();
    const isWardrobeOpen    = useGameStore(s => s.isWardrobeOpen);
    const closeWardrobeAll  = useGameStore(s => s.closeWardrobeAll);
    const chickenColorIdx = useGameStore(s => s.chickenColorIdx);
    const unlockedItems   = useGameStore(s => s.unlockedItems);
    const setChickenColor = useGameStore(s => s.setChickenColor);
    const buyChickenColor = useGameStore(s => s.buyChickenColor);
    const totalCoins      = useGameStore(s => s.totalCoins);

    const [previewIdx, setPreviewIdx] = useState(0);

    useEffect(() => {
        if (isWardrobeOpen) {
            const si = SKINS.findIndex(s => s.colorIdx === chickenColorIdx);
            setPreviewIdx(si >= 0 ? si : 0);
        }
    }, [isWardrobeOpen]);

    if (!isWardrobeOpen) return null;

    const skin       = SKINS[previewIdx];
    const isOwned    = skin.cost === 0 || unlockedItems.includes(skin.id);
    const canAfford  = totalCoins >= skin.cost;
    const isSelected = chickenColorIdx === skin.colorIdx;

    const goTo = (i) => { if (i >= 0 && i < SKINS.length) setPreviewIdx(i); };

    const handleChoose = () => {
        if (isSelected) return;
        if (isOwned) { setChickenColor(skin.colorIdx); }
        else if (canAfford) { buyChickenColor(skin.colorIdx); }
    };

    let btnLabel, btnBg, btnColor, btnCursor, btnShadow, btnTextShadow, btnBorderGradient;
    if (isSelected) {
        btnLabel = t.btnSelected;
        btnBg = 'linear-gradient(to top, #0F9B63 0%, #2DE060 100%)';
        btnColor = '#fff'; btnCursor = 'default';
        btnShadow = '#096A5B';
        btnTextShadow = '0 3px 0px #096A5B';
        btnBorderGradient = 'linear-gradient(#A2FFBC, #A2FFBC), linear-gradient(to bottom, #A2FFBC00 80%, #A2FFBC66 100%)';
    } else if (isOwned) {
        btnLabel = t.btnSelect;
        btnBg = OG_GRAD;
        btnColor = '#fff'; btnCursor = 'pointer';
        btnShadow = C_BTN_SHADOW;
        btnTextShadow = `0 3px 0px ${C_BTN_SHADOW}`;
        btnBorderGradient = 'linear-gradient(#FFFFFF, #FFFFFF), linear-gradient(to bottom, #FFFFFF00 80%, #FFFFFF66 100%)';
    } else if (canAfford) {
        btnLabel = t.btnBuy(skin.cost);
        btnBg = OG_GRAD;
        btnColor = '#fff'; btnCursor = 'pointer';
        btnShadow = 'inset 0 -4px 0 rgba(0,0,0,0.28), inset 0 2px 0 rgba(255,255,255,0.2)';
        btnTextShadow = `0 3px 0px ${C_BTN_SHADOW}`;
        btnBorderGradient = 'linear-gradient(#FFFFFF, #FFFFFF), linear-gradient(to bottom, #FFFFFF00 80%, #FFFFFF66 100%)';
    } else {
        btnLabel = t.btnNotEnough(skin.cost);
        btnBg = '494D5E99';
        btnColor = 'rgba(255,255,255,0.6)'; btnCursor = 'default'; btnShadow = 'none';
        btnTextShadow = '0 3px 0px #292E42';
        btnBorderGradient = 'linear-gradient(#FFFFFF, #FFFFFF), linear-gradient(to bottom, #FFFFFF00 30%, #FFFFFF33 100%)';
    }

    return (
        <div
            onPointerDown={closeWardrobeAll}
            style={{
            position: 'fixed', inset: 0, zIndex: 2200,
            background: OVERLAY_BG,
            backdropFilter: 'blur(10px)',
            WebkitBackdropFilter: 'blur(10px)',
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', justifyContent: 'center',
            paddingTop: 'max(env(safe-area-inset-top, 0px), 16px)',
            paddingBottom: 'calc(96px + env(safe-area-inset-bottom, 0px))',
            paddingLeft: 18, paddingRight: 18,
            gap: 12,
        }}>
            <ScreenFade />
            {/* ── Card ── */}
            <GameCard zIndex={1} style={{ alignItems: 'center' }}>
                {/* Header */}
                <div style={{ textAlign: 'center', padding: '28px 56px 0', flexShrink: 0 }}>
                    <div style={{
                        fontFamily: F_TITLE,
                        fontSize: 'clamp(24px, 5.5vw, 24px)',
                        fontWeight: 700,
                        color: '#fff',
                        letterSpacing: 2,
                        textShadow: '0 4px 0 #181A27',
                        lineHeight: 1.4,
                    }}>{skin.name.toUpperCase()}</div>
                    <div style={{
                        fontFamily: F_UI,
                        fontSize: 'clamp(14px, 3vw, 14px)',
                        fontWeight: 600,
                        color: 'rgba(255,255,255,0.6)',
                        marginTop: 6,
                        textShadow: '0 4px 0 #181A2799',
                        lineHeight: 1.4,
                    }}>{t.skinDesc[skin.id]}</div>
                </div>

                {/* 3D area */}
                <div style={{ position: 'relative', height: 'min(460px, 68vw)', flexShrink: 0 }}>
                    <Canvas
                        camera={{ position: [0, 0.5, 5], fov: 35 }}
                        gl={{ antialias: true, alpha: true }}
                        style={{ background: 'transparent', width: '100%', height: '100%' }}
                    >
                        <Suspense fallback={null}>
                            <hemisphereLight args={['#b8d8f8', '#d4a85a', 1.6]} />
                            <directionalLight position={[4, 8, 4]} intensity={3.5} color="#ffcc66" />
                            <directionalLight position={[-6, 4, 8]} intensity={0.6} color="#88bbff" />
                            <PreviewChicken colorIdx={skin.colorIdx} model={skin.model} skinType={skin.skinType} meshNames={skin.meshNames} overlayName={skin.overlayName} />
                            <OrbitControls enablePan={false} enableZoom={false}
                                minPolarAngle={Math.PI * 0.3} maxPolarAngle={Math.PI * 0.65} />
                        </Suspense>
                    </Canvas>

                    {/* Left arrow */}
                    <button onPointerDown={() => goTo(previewIdx - 1)} style={{
                        position: 'absolute', left: 8, top: '50%', transform: 'translateY(-50%)',
                        width: 36, height: 36, borderRadius: 8,
                        background: 'none', border: 'none',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        cursor: previewIdx === 0 ? 'default' : 'pointer',
                        WebkitTapHighlightColor: 'transparent', padding: 0,
                    }}>
                        <ArrowLeft disabled={previewIdx === 0} />
                    </button>

                    {/* Right arrow */}
                    <button onPointerDown={() => goTo(previewIdx + 1)} style={{
                        position: 'absolute', right: 8, top: '50%', transform: 'translateY(-50%)',
                        width: 36, height: 36, borderRadius: 8,
                        background: 'none', border: 'none',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        cursor: previewIdx === SKINS.length - 1 ? 'default' : 'pointer',
                        WebkitTapHighlightColor: 'transparent', padding: 0,
                    }}>
                        <ArrowRight disabled={previewIdx === SKINS.length - 1} />
                    </button>

                    {/* Dots */}
                    <div style={{
                        position: 'absolute', bottom: 10, left: 0, right: 0,
                        display: 'flex', justifyContent: 'center', gap: 6,
                        pointerEvents: 'none',
                    }}>
                        {SKINS.map((_, i) => (
                            i === previewIdx ? (
                                <div key={i} style={{ position: 'relative', width: 16, height: 16, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ position: 'absolute', inset: 0 }}>
                                        <circle opacity="0.3" cx="8" cy="8" r="7.25" stroke="white" strokeWidth="1.5"/>
                                    </svg>
                                    <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#fff' }} />
                                </div>
                            ) : (
                                <div key={i} style={{
                                    width: 8, height: 8,
                                    alignSelf: 'center',
                                    borderRadius: '50%',
                                    background: '#181A27',
                                }} />
                            )
                        ))}
                    </div>
                </div>

                {/* ── Action button inside card ── */}
                <div style={{ padding: '24px 16px 48px', width: '75%', flexShrink: 0, boxSizing: 'border-box' }}>
                    <GameButton
                        onPointerDown={handleChoose}
                        shadowColor={btnShadow}
                        borderGradient={btnBorderGradient}
                        bg={btnBg}
                        color={btnColor}
                        textShadow={btnTextShadow}
                        cursor={btnCursor}
                        style={{ fontFamily: F_TITLE, fontSize: 24, fontWeight: 700 }}
                    >{btnLabel}</GameButton>
                </div>
            </GameCard>

        </div>
    );
}
