function UpgradeMenu({ isFirst, onSelect }) {
    const t = useT();
    const [timeLeft, setTimeLeft] = useState(UPGRADE_MENU_TIMEOUT);

    useEffect(() => {
        if (isFirst) return;
        const id = setInterval(() => {
            setTimeLeft(t => {
                const next = t - 0.05;
                if (next <= 0) { clearInterval(id); onSelect('slowmo'); return 0; }
                return next;
            });
        }, 50);
        return () => clearInterval(id);
    }, [isFirst, onSelect]);

    return (
        <div style={{
            position: 'absolute', inset: 0,
            background: 'rgba(10,5,20,0.72)',
            backdropFilter: 'blur(10px)',
            WebkitBackdropFilter: 'blur(10px)',
            display: 'flex', flexDirection: 'column', alignItems: 'center',
            paddingTop: 'max(env(safe-area-inset-top, 0px), 16px)',
            paddingBottom: 16,
            paddingLeft: 18, paddingRight: 18,
            gap: 12,
            zIndex: 600, pointerEvents: 'auto',
        }}>
            <ScreenFade />
            <div style={{
                width: '100%', maxWidth: 420,
                zIndex: 1,
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 32,
                flex: 1, minHeight: 0,
                paddingTop: 46,
            }}>
                <GameCard
                    zIndex={20}
                    wrapperStyle={{ position: 'relative', width: '90%' }}
                    style={{
                        padding: '4px 4px',
                        height: 48,
                        display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'center',
                    }}
                >
                    <div style={{
                        fontFamily: F_TITLE,
                        textAlign: 'center',
                        fontSize: 'clamp(20px, 5vw, 20px)',
                        fontWeight: 700, color: '#fff',
                        textShadow: '0 4px 0px #181A27',
                    }}>{t.chooseUpgrade}</div>
                </GameCard>

                <GameCard
                    zIndex={1}
                    wrapperStyle={{ position: 'relative', marginTop: -36, flex: 1, minHeight: 0, maxHeight: 590, display: 'flex', flexDirection: 'column' }}
                    style={{
                        flex: 1, minHeight: 0,
                        display: 'flex', flexDirection: 'column',
                        overflow: 'hidden',
                    }}
                >
                    <div style={{ height: 32, flexShrink: 0 }} />

                    {!isFirst && (
                        <div style={{ padding: '0 16px 8px', flexShrink: 0 }}>
                            <div style={{ width: '100%', height: 3, background: 'rgba(255,255,255,0.1)', borderRadius: 2, overflow: 'hidden' }}>
                                <div style={{
                                    height: '100%', background: OG_GRAD, borderRadius: 2,
                                    width: `${(timeLeft / UPGRADE_MENU_TIMEOUT) * 100}%`,
                                    transition: 'width 0.05s linear',
                                }} />
                            </div>
                        </div>
                    )}

                    <div style={{ padding: '0 16px 16px 12px', display: 'flex', flexDirection: 'column', gap: 24 }}>
                        {Object.entries(t.upgrades).map(([id, u]) => (
                            <UpgradeRow
                                key={id}
                                id={id}
                                color={UPGRADE_COLORS[id]}
                                icon={UPGRADE_ICONS[id]}
                                title={u.title}
                                desc={u.desc}
                                onSelect={onSelect}
                            />
                        ))}
                    </div>
                </GameCard>
            </div>
        </div>
    );
}

