export default function Overlay() {
    const t = useT();
    const isStarted   = useGameStore(s => s.isStarted);
    const score       = useGameStore(s => s.score);
    const isDead      = useGameStore(s => s.isDead);
    const isFlashed   = useGameStore(s => s.isFlashed);
    const restart     = useGameStore(s => s.restart);
    const goToLobby   = useGameStore(s => s.goToLobby);
    const deathType   = useGameStore(s => s.deathType);
    const totalCoins  = useGameStore(s => s.totalCoins);
    const highScore   = useGameStore(s => s.highScore);
    const topScores   = useGameStore(s => s.topScores);
    const isNewRecord = useGameStore(s => s.isNewRecord);
    const isAuth         = useGameStore(s => s.isAuth);
    const setAuth        = useGameStore(s => s.setAuth);
    const isAuthModalOpen  = useGameStore(s => s.isAuthModalOpen);
    const openAuthModal    = useGameStore(s => s.openAuthModal);
    const closeAuthModal   = useGameStore(s => s.closeAuthModal);
    const bombActive     = useGameStore(s => s.bombActive);
    const sniperActive   = useGameStore(s => s.sniperActive);
    
    // Медали, апгрейды и бустеры
    const medalPartsCollected    = useGameStore(s => s.medalPartsCollected);
    const upgradeMenuOpen        = useGameStore(s => s.upgradeMenuOpen);
    const upgradeMenuIsFirst     = useGameStore(s => s.upgradeMenuIsFirst);
    const selectUpgrade          = useGameStore(s => s.selectUpgrade);
    const invulnerabilityActive  = useGameStore(s => s.invulnerabilityActive);
    const invulnerabilityHitsLeft= useGameStore(s => s.invulnerabilityHitsLeft);
    const slowMotionActive       = useGameStore(s => s.slowMotionActive);
    const scoreBoostActive       = useGameStore(s => s.scoreBoostActive);

    const MILESTONES = [
        { score: 50,   icon: '⭐', label: '50' },
        { score: 100,  icon: '🌟', label: '100' },
        { score: 250,  icon: '💫', label: '250' },
        { score: 500,  icon: '🔥', label: '500' },
        { score: 1000, icon: '👑', label: '1000' },
    ];

    const [showMenu, setShowMenu]       = useState(false);
    const [showFaq,  setShowFaq]        = useState(false);
    const [recordPanelDismissed, setRecordPanelDismissed] = useState(false);
    const [medalRevealOpen, setMedalRevealOpen] = useState(false);
    const [coinPop, setCoinPop]     = useState(false);
    const [recordAnim,  setRecordAnim]    = useState(false);
    const [milestoneAnim, setMilestoneAnim] = useState(null); // { icon, label }
    const [earnedMilestones, setEarnedMilestones] = useState([]);
    // Медаль: анимация полёта + визуально открытые части
    const [medalAnim, setMedalAnim]             = useState(null); // 'up'|'top'|'down'|null
    const [visualCollected, setVisualCollected] = useState(() => [...medalPartsCollected]);
    // Экран 3D-медали при первом сборе
    const [medalRevealDismissed, setMedalRevealDismissed] = useState(false);

    // Локальные таймеры бустеров — обновляются через setInterval, не через Zustand
    const [slowTimeLeft,  setSlowTimeLeft]  = useState(0);
    const [boostTimeLeft, setBoostTimeLeft] = useState(0);
    useEffect(() => {
        if (!slowMotionActive) { setSlowTimeLeft(0); return; }
        setSlowTimeLeft(Math.max(0, (upgradeTimers.slowMotionEndAt - performance.now()) / 1000));
        const iv = setInterval(() => {
            const left = Math.max(0, (upgradeTimers.slowMotionEndAt - performance.now()) / 1000);
            setSlowTimeLeft(left);
        }, 250);
        return () => clearInterval(iv);
    }, [slowMotionActive]);
    useEffect(() => {
        if (!scoreBoostActive) { setBoostTimeLeft(0); return; }
        setBoostTimeLeft(Math.max(0, (upgradeTimers.scoreBoostEndAt - performance.now()) / 1000));
        const iv = setInterval(() => {
            const left = Math.max(0, (upgradeTimers.scoreBoostEndAt - performance.now()) / 1000);
            setBoostTimeLeft(left);
        }, 250);
        return () => clearInterval(iv);
    }, [scoreBoostActive]);

    const prevCoins        = useRef(totalCoins);
    const prevPartLen      = useRef(0);
    const currentDate      = useRef(null);
    const firedMilestones  = useRef(new Set());

    // Сброс dismissed когда меню апгрейда закрывается
    useEffect(() => {
        if (!upgradeMenuOpen) setMedalRevealDismissed(false);
    }, [upgradeMenuOpen]);

    // Pop-анимация монет
    useEffect(() => {
        if (totalCoins !== prevCoins.current) {
            prevCoins.current = totalCoins;
            setCoinPop(true);
            const t = setTimeout(() => setCoinPop(false), 350);
            return () => clearTimeout(t);
        }
    }, [totalCoins]);

    // Анимация сбора части медали: медаль летит вверх → кусок исчезает → возвращается
    useEffect(() => {
        const cur  = medalPartsCollected.length;
        const prev = prevPartLen.current;

        // Последний кусок: store сбрасывается с ≥4 до 0
        const isLastPiece = cur === 0 && prev >= 4;

        if (!isLastPiece) {
            if (cur <= prev) { prevPartLen.current = cur; return; }
            const newPart = medalPartsCollected[cur - 1];
            prevPartLen.current = cur;

            // Сразу раскрываем все уже собранные части (если предыдущая анимация не успела)
            if (cur > 1) {
                const alreadyDone = medalPartsCollected.slice(0, cur - 1);
                setVisualCollected(p => {
                    const merged = [...p];
                    for (const part of alreadyDone) if (!merged.includes(part)) merged.push(part);
                    return merged;
                });
            }

            setMedalAnim('up');
            const t1 = setTimeout(() => {
                setMedalAnim('top');
                setVisualCollected(p => p.includes(newPart) ? p : [...p, newPart]);
            }, 700);
            const t2 = setTimeout(() => setMedalAnim('down'), 1500);
            const t3 = setTimeout(() => setMedalAnim(null), 2200);
            return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
        }

        // Все 5 частей собраны — полное открытие (меню апгрейда откроется само)
        prevPartLen.current = 0;
        const ALL_PARTS = ['medal_part1','medal_part2','medal_part3','medal_part4','medal_part5'];
        setMedalAnim('up');
        const t1 = setTimeout(() => {
            setMedalAnim('top');
            setVisualCollected(ALL_PARTS);
        }, 700);
        const t2 = setTimeout(() => setMedalAnim('down'), 1500);
        const t3 = setTimeout(() => { setMedalAnim(null); setVisualCollected([]); }, 2200);
        return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
    }, [medalPartsCollected.length]);

    // Анимация рекорда — срабатывает один раз за забег при пересечении highScore
    const prevScore     = useRef(0);
    const recordFired   = useRef(false);
    useEffect(() => {
        const prev = prevScore.current;
        prevScore.current = score;
        if (!isDead && highScore > 0 && score > highScore && prev <= highScore && !recordFired.current) {
            recordFired.current = true;
            SoundManager.play('highscore', false);
            SoundManager.play('score100', false);
            setRecordAnim(true);
            const t = setTimeout(() => setRecordAnim(false), 2200);
            return () => clearTimeout(t);
        }
    }, [score]);

    // Milestone-эффекты: срабатывают при пересечении отметки
    useEffect(() => {
        if (isDead) return;
        for (const m of MILESTONES) {
            if (score >= m.score && !firedMilestones.current.has(m.score)) {
                firedMilestones.current.add(m.score);
                setEarnedMilestones(prev => [...prev, m]);
                SoundManager.play('xpMilestone', false);
                setMilestoneAnim(m);
                setTimeout(() => setMilestoneAnim(null), 1800);
                break; // по одной за раз
            }
        }
    }, [score]);

    // Задержанный показ экрана смерти
    useEffect(() => {
        let timer;
        if (isDead) {
            currentDate.current = Date.now();
            timer = setTimeout(() => {
                setShowMenu(true);
                if (isNewRecord) SoundManager.play('xpLevelup', false);
            }, 600);
        } else {
            setShowMenu(false);
            setShowFaq(false);
            setRecordPanelDismissed(false);
            closeAuthModal();
            setRecordAnim(false);
            setMilestoneAnim(null);
            setEarnedMilestones([]);
            setMedalAnim(null);
            setVisualCollected([]);
            prevPartLen.current = 0;
            prevScore.current = 0;
            recordFired.current = false;
            firedMilestones.current = new Set();
            currentDate.current = null;
        }
        return () => clearTimeout(timer);
    }, [isDead]);

    const bonusCoins = score >= 50 ? Math.floor(score / 50) * 20 : 0;

    return (
        <>
            {/* FLASH-эффект */}
            <div style={{
                position: 'fixed', inset: 0,
                backgroundColor: 'white',
                transition: isFlashed ? 'none' : 'opacity 0.5s ease-out',
                opacity: isFlashed ? 1 : 0,
                pointerEvents: 'none',
                zIndex: 9999,
            }} />

            {/* ── Vignette щита — тускнеет по мере потери зарядов ───────────── */}
            <div style={{
                position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 8,
                boxShadow: 'inset 0 0 90px 30px rgba(40,120,255,0.35)',
                opacity: invulnerabilityActive
                    ? invulnerabilityHitsLeft === 1 ? 0.35 : invulnerabilityHitsLeft === 2 ? 0.65 : 1
                    : 0,
                transition: 'opacity 0.3s ease',
            }} />

            {/* ── Vignette score boost (золотой) ────────────────────────────── */}
            <div style={{
                position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 8,
                boxShadow: 'inset 0 0 90px 30px rgba(255,200,0,0.28)',
                opacity: scoreBoostActive ? 1 : 0,
                transition: 'opacity 0.4s ease',
            }} />

            <div style={{
                position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
                pointerEvents: 'none', fontFamily: 'monospace', color: '#ffcc00',
                zIndex: 10,
                opacity: isStarted ? 1 : 0,
                transition: isStarted ? 'opacity 1.0s ease' : 'none',
            }}>
                {/* ── HUD ───────────────────────────────────────────────────── */}
                {!showMenu && (
                    <div style={{
                        position: 'absolute',
                        top: 'min(5vh, 28px)',
                        left: 'min(5vw, 20px)',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'flex-start',
                        gap: 2,
                        userSelect: 'none',
                    }}>
                        {/* Score */ }
                        <span style={{ filter: 'drop-shadow(0px 2px 0px #181A27)' }}>
                            <span style={{
                                fontFamily: F_TITLE,
                                fontSize: 'clamp(40px, 8vw, 40px)',
                                fontWeight: 700,
                                background: '#fff',
                                WebkitBackgroundClip: 'text',
                                backgroundClip: 'text',
                                color: 'transparent',
                                WebkitTextStroke: '2px #181A27',
                                paintOrder: 'fill stroke',
                                lineHeight: 1,
                            }}>
                                {score}
                            </span>
                        </span>
                        {/* Coins */ }
                        <span style={{ filter: 'drop-shadow(0px 2px 0px #181A27)' }}>
                            <span style={{
                                fontFamily: F_TITLE,
                                fontSize: 'clamp(40px, 8vw, 40px)',
                                fontWeight: 700,
                                background: 'linear-gradient(to bottom, #FFB60C, #FF931F)',
                                WebkitBackgroundClip: 'text',
                                backgroundClip: 'text',
                                color: 'transparent',
                                WebkitTextStroke: '2px #181A27',
                                paintOrder: 'stroke fill',
                                lineHeight: 1,
                                animation: coinPop ? 'coinPop 0.35s cubic-bezier(0.36,0.07,0.19,0.97)' : 'none',
                            }}>
                                {totalCoins}
                            </span>
                        </span>
                    </div>
                )}

                {/* ── Медаль с тёмными секторами (bottom-left, анимация полёта) ── */}
                {!showMenu && (() => {
                    const SZ = 64, CX = 32, CY = 32, R = 34;
                    const PARTS = ['medal_part1','medal_part5','medal_part4','medal_part3','medal_part2'];
                    // Crack angles from Blender ref — where each divider meets the rim (°CW from top)
                    const CRACK_ANGLES = [5, 55, 140, 205, 285];
                    // Jagged edge from center to rim — deterministic offsets per angle
                    const jaggedEdge = (angleDeg, steps = 5) => {
                        const rad  = (angleDeg - 90) * Math.PI / 180;
                        const perp = rad + Math.PI / 2;
                        const pts  = [];
                        for (let k = 1; k <= steps; k++) {
                            const t   = k / steps;
                            const r   = t * R;
                            const env = Math.sin(t * Math.PI); // peaks mid-way, zero at ends
                            const jag = Math.sin(angleDeg * 0.13 + k * 2.71) * 9.0 * env;
                            pts.push([
                                CX + r * Math.cos(rad) + jag * Math.cos(perp),
                                CY + r * Math.sin(rad) + jag * Math.sin(perp),
                            ]);
                        }
                        return pts; // last point lands on rim
                    };
                    const makeSectorPath = (a0, a1) => {
                        const edge0  = jaggedEdge(a0);
                        const edge1  = jaggedEdge(a1);
                        // Normalise: ensure arc goes clockwise (a1 > a0); handles 285°→5° wrap-around
                        const a1eff  = a1 <= a0 ? a1 + 360 : a1;
                        // Arc approximated as polyline
                        const arcPts = [];
                        const steps  = 7;
                        for (let k = 1; k < steps; k++) {
                            const deg = a0 + (a1eff - a0) * k / steps;
                            const r   = (deg - 90) * Math.PI / 180;
                            arcPts.push([CX + R * Math.cos(r), CY + R * Math.sin(r)]);
                        }
                        const all = [
                            [CX, CY],
                            ...edge0,
                            ...arcPts,
                            ...edge1.slice().reverse(),
                        ];
                        return all.map((p, i) =>
                            `${i === 0 ? 'M' : 'L'} ${p[0].toFixed(1)} ${p[1].toFixed(1)}`
                        ).join(' ') + ' Z';
                    };
                    const flying = medalAnim === 'up' || medalAnim === 'top';
                    // Nested X+Y divs for smooth arc: X=ease-out (rushes right first),
                    // Y=ease-in (rises slowly at start) → natural right-bowing arc
                    // X: very aggressive ease-out (rushes right fast, arc bows right)
                    // Y: moderate ease-out (fast start, slow end — user request)
                    // Both decelerate toward the end = non-linear fast→slow feel
                    // X: move medal's left-edge to center, then subtract half its width
                    // 50vw - left(min(5vw,28px)) - halfWidth(clamp(50px,8.5vw,70px))
                    const CX_TO = 'calc(50vw - min(5vw, 28px) - clamp(50px, 8.5vw, 70px))';
                    // Y: move medal's center from bottom(~90px+halfH) up to top (~15vh from top)
                    const CY_TO = 'calc(-85vh + 90px + clamp(50px, 8.5vw, 70px))';
                    const xStyle = medalAnim === 'up'   ? { animation: 'medalX_up 0.7s cubic-bezier(0,0,0.15,1) forwards' }
                                 : medalAnim === 'top'  ? { transform: `translateX(${CX_TO})` }
                                 : medalAnim === 'down' ? { animation: 'medalX_down 0.7s cubic-bezier(0,0,0.15,1) forwards' }
                                 : { transform: 'translateX(0)' };
                    const yStyle = medalAnim === 'up'   ? { animation: 'medalY_up 0.7s cubic-bezier(0,0,0.4,1) forwards' }
                                 : medalAnim === 'top'  ? { transform: `translateY(${CY_TO}) scale(1.15)` }
                                 : medalAnim === 'down' ? { animation: 'medalY_down 0.7s cubic-bezier(0,0,0.4,1) forwards' }
                                 : { transform: 'translateY(0) scale(1)' };
                    return (
                        <div style={{
                            position: 'absolute',
                            bottom: 'max(env(safe-area-inset-bottom, 0px) + 70px, 90px)',
                            left: 'min(5vw, 28px)',
                            zIndex: flying ? 50 : 15,
                        }}>
                        <div style={xStyle}>
                        <div style={yStyle}>
                            <div style={{
                                position: 'relative',
                                width: 'clamp(100px, 17vw, 140px)',
                                height: 'clamp(100px, 17vw, 140px)',
                            }}>
                                <img
                                    src="/images/medalRio2026.webp"
                                    alt="medal"
                                    style={{ width: '100%', height: '100%', objectFit: 'contain', display: 'block' }}
                                />
                                <svg
                                    viewBox={`0 0 ${SZ} ${SZ}`}
                                    style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }}
                                >
                                    <defs>
                                        <clipPath id="medalCircle">
                                            <circle cx={CX} cy={CY} r={30} />
                                        </clipPath>
                                    </defs>
                                    <g clipPath="url(#medalCircle)">
                                        {PARTS.map((p, i) => {
                                            if (visualCollected.includes(p)) return null;
                                            return (
                                                <path key={p}
                                                    d={makeSectorPath(CRACK_ANGLES[i], CRACK_ANGLES[(i + 1) % 5])}
                                                    fill="rgba(0,0,0,0.55)"
                                                />
                                            );
                                        })}
                                    </g>
                                </svg>
                            </div>
                        </div></div></div>
                    );
                })()}

                {/* ── Таймеры бустеров (центр сверху) ────────────────────────── */}
                {(invulnerabilityActive || scoreBoostActive || slowMotionActive) && (
                    <div style={{
                        position: 'absolute',
                        top: 'min(5vh, 30px)',
                        left: '50%',
                        transform: 'translateX(-50%)',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        gap: '6px',
                        pointerEvents: 'none',
                    }}>
                        {invulnerabilityActive && (
                            <div style={{
                                padding: '8px 18px',
                                background: 'rgba(0,0,0,0.65)',
                                border: `1px solid rgba(0,255,136,${invulnerabilityHitsLeft === 1 ? 0.3 : 0.5})`,
                                borderRadius: '6px',
                                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px',
                            }}>
                                <div style={{ fontSize: '9px', letterSpacing: '2px', color: '#00ff88', textShadow: '0 0 8px rgba(0,255,136,0.6)' }}>{t.boostLabel_shield}</div>
                                <div style={{ display: 'flex', gap: '6px' }}>
                                    {Array.from({ length: UPGRADE_INVUL_HITS }, (_, i) => (
                                        <div key={i} style={{
                                            width: '18px', height: '18px', borderRadius: '50%',
                                            background: i < invulnerabilityHitsLeft ? '#00ff88' : 'rgba(255,255,255,0.1)',
                                            border: `2px solid ${i < invulnerabilityHitsLeft ? '#00ff88' : 'rgba(255,255,255,0.15)'}`,
                                            transition: 'background 0.2s, border-color 0.2s',
                                        }} />
                                    ))}
                                </div>
                            </div>
                        )}
                        {slowMotionActive && (
                            <div style={{
                                padding: '8px 18px',
                                background: 'rgba(0,0,0,0.65)',
                                border: '1px solid rgba(136,204,255,0.5)',
                                borderRadius: '6px',
                                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px',
                            }}>
                                <div style={{ fontSize: '9px', letterSpacing: '2px', color: '#88ccff', textShadow: '0 0 8px rgba(136,204,255,0.6)' }}>{t.boostLabel_slowmo}</div>
                                <div style={{ fontSize: 'clamp(16px, 5vw, 26px)', fontWeight: '900', color: '#88ccff', lineHeight: 1 }}>
                                    {Math.ceil(slowTimeLeft)}s
                                </div>
                                <div style={{ width: '100px', height: '3px', background: 'rgba(0,0,0,0.5)', borderRadius: '2px', overflow: 'hidden' }}>
                                    <div style={{ width: `${(slowTimeLeft / UPGRADE_SLOW_DURATION) * 100}%`, height: '100%', background: 'linear-gradient(90deg,#88ccff,#4499dd)', transition: 'width 0.25s linear' }} />
                                </div>
                            </div>
                        )}
                        {scoreBoostActive && (
                            <div style={{
                                padding: '8px 18px',
                                background: 'rgba(0,0,0,0.65)',
                                border: '1px solid rgba(255,204,0,0.5)',
                                borderRadius: '6px',
                                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px',
                            }}>
                                <div style={{ fontSize: '9px', letterSpacing: '2px', color: '#ffcc00', textShadow: '0 0 8px rgba(255,204,0,0.6)' }}>{t.boostLabel_doublescore}</div>
                                <div style={{ fontSize: 'clamp(16px, 5vw, 26px)', fontWeight: '900', color: '#ffcc00', lineHeight: 1 }}>
                                    {Math.ceil(boostTimeLeft)}s
                                </div>
                                <div style={{ width: '100px', height: '3px', background: 'rgba(0,0,0,0.5)', borderRadius: '2px', overflow: 'hidden' }}>
                                    <div style={{ width: `${(boostTimeLeft / UPGRADE_SCORE_DURATION) * 100}%`, height: '100%', background: 'linear-gradient(90deg,#ffcc00,#ff8800)', transition: 'width 0.25s linear' }} />
                                </div>
                            </div>
                        )}
                    </div>
                )}


                {/* ── Значки рекорда + milestone (низ-право) ───────────────────── */}
                {!showMenu && !isDead && (earnedMilestones.length > 0 || (recordFired.current && score > highScore)) && (
                    <div style={{
                        position: 'absolute',
                        bottom: 'max(env(safe-area-inset-bottom, 0px) + 70px, 90px)',
                        right: 'min(5vw, 28px)',
                        display: 'flex', flexDirection: 'column-reverse', alignItems: 'center', gap: '6px',
                        pointerEvents: 'none',
                    }}>
                        {/* Milestone-значки снизу вверх */}
                        {earnedMilestones.map(m => (
                            <div key={m.score} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1px' }}>
                                <div style={{ fontSize: 'clamp(20px, 6vw, 28px)' }}>{m.icon}</div>
                                <div style={{ fontSize: '7px', letterSpacing: '1px', color: '#ffffaa', fontFamily: 'monospace' }}>{m.label}</div>
                            </div>
                        ))}
                        {/* Рекорд-значок сверху стека */}
                        {recordFired.current && score > highScore && (
                            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1px' }}>
                                <div style={{ fontSize: 'clamp(24px, 7vw, 34px)' }}>🏆</div>
                                <div style={{ fontSize: '7px', letterSpacing: '1px', color: '#ffcc00', fontFamily: 'monospace', textShadow: '0 0 5px #ffcc00' }}>{t.recordLabel}</div>
                            </div>
                        )}
                    </div>
                )}

                {/* ── Fly-анимация milestone ────────────────────────────────────── */}
                {milestoneAnim && (
                    <div style={{
                        position: 'absolute',
                        top: '12%', left: '50%',
                        transform: 'translateX(-50%)',
                        display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px',
                        pointerEvents: 'none',
                        animation: 'recordFly 1.8s cubic-bezier(0.4,0,0.2,1) forwards',
                        zIndex: 20,
                    }}>
                        <div style={{ fontSize: '44px' }}>{milestoneAnim.icon}</div>
                        <div style={{ fontSize: '12px', letterSpacing: '3px', color: '#ffffaa', fontFamily: 'monospace', textShadow: '0 0 10px #ffff88' }}>
                            {milestoneAnim.label}{t.ptsSuffix}
                        </div>
                    </div>
                )}

                {/* ── Анимация нового рекорда (центр → низ-право) ─────────────── */}
                {recordAnim && (
                    <div style={{
                        position: 'absolute',
                        top: '10%', left: '50%',
                        transform: 'translateX(-50%)',
                        display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px',
                        pointerEvents: 'none',
                        animation: 'recordFly 2.2s cubic-bezier(0.4,0,0.2,1) forwards',
                        zIndex: 20,
                    }}>
                        <div style={{ fontSize: '40px' }}>🏆</div>
                        <div style={{ fontSize: '11px', letterSpacing: '3px', color: '#ffcc00', fontFamily: 'monospace', textShadow: '0 0 10px #ffcc00' }}>{t.newRecord}</div>
                    </div>
                )}


                {/* ── Панель нового рекорда (перед экраном смерти) ─────────── */}
                {isDead && showMenu && isNewRecord && !recordPanelDismissed && (
                    <NewRecordPanel
                        score={score}
                        onContinue={() => setRecordPanelDismissed(true)}
                    />
                )}

                {/* ── Экран смерти ──────────────────────────────────────────── */}
                {isDead && showMenu && (!isNewRecord || recordPanelDismissed) && (
                    <div
                        onPointerDown={!isAuthModalOpen ? restart : undefined}
                        style={{
                            position: 'absolute', inset: 0,
                            backgroundColor: 'rgba(0,0,0,0.65)',
                            backdropFilter: 'blur(6px)',
                            WebkitBackdropFilter: 'blur(6px)',
                            display: 'flex', flexDirection: 'column', alignItems: 'center',
                            justifyContent: 'center', pointerEvents: 'auto',
                            padding: '20px', zIndex: 2000,
                            cursor: !isAuthModalOpen ? 'pointer' : 'default',
                            WebkitTapHighlightColor: 'transparent',
                        }}
                    >
                        { isAuthModalOpen ? (
                            <>
                                <ScreenFade />
                                <AuthModal
                                    onClose={closeAuthModal}
                                    onAuth={(email) => {
                                        setAuth(true);
                                        closeAuthModal();
                                    }}
                                />
                            </>
                        ) : (
                            <>
                                <ScreenFade />
                                <DeathCard
                                    score={score}
                                    isAuth={isAuth}
                                    onContinue={(e) => { e?.stopPropagation(); goToLobby(); }}
                                    onLogin={(e) => { e?.stopPropagation(); openAuthModal(); }}
                                />
                            </>
                        )}
                    </div>
                )}


                {/* ── Меню апгрейда ─────────────────────────────────────── */}
                {upgradeMenuOpen && !isDead && (
                    <UpgradeMenu isFirst={upgradeMenuIsFirst} onSelect={selectUpgrade} />
                )}

                {/* ── 3D-экран медали (первый раз или из меню) ───────────── */}
                {((upgradeMenuOpen && !isDead && upgradeMenuIsFirst && !medalRevealDismissed) || medalRevealOpen) && (
                    <MedalReveal onClose={() => { setMedalRevealDismissed(true); setMedalRevealOpen(false); }} />
                )}

                {/* ── Бомба (стоишь на месте) ─────────────────────────────── */}
                {bombActive && !isDead && <BombHUD />}

                {/* ── Прицел снайпера (идёшь назад) ───────────────────────── */}
                {sniperActive && !isDead && <SniperHUD />}

                <style>{`
                    .death-screen { animation: screenFade 0.4s ease-out; }
                    @keyframes screenFade {
                        from { opacity: 0; transform: scale(1.05); }
                        to   { opacity: 1; transform: scale(1); }
                    }
                    .new-record-banner { animation: recordPop 0.5s cubic-bezier(0.22,1,0.36,1); }
                    @keyframes recordPop {
                        0%   { transform: scale(0.4) translateY(-10px); opacity: 0; }
                        70%  { transform: scale(1.1) translateY(0); opacity: 1; }
                        100% { transform: scale(1); opacity: 1; }
                    }
                    @keyframes bombShake {
                        0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }
                        25%      { transform: translate(calc(-50% - 3px), calc(-50% + 2px)) rotate(-2deg); }
                        75%      { transform: translate(calc(-50% + 3px), calc(-50% - 2px)) rotate(2deg); }
                    }
                    @keyframes medalCollectFly {
                        0%   { opacity: 0; transform: translateX(-50%) scale(0.4); }
                        20%  { opacity: 1; transform: translateX(-50%) scale(1.3); }
                        100% { opacity: 0; transform: translateX(calc(-50% - 38vw)) translateY(60vh) scale(0.6); }
                    }
                    @keyframes medalX_up   { from { transform: translateX(0); } to { transform: translateX(calc(50vw - min(5vw, 28px) - clamp(50px, 8.5vw, 70px))); } }
                    @keyframes medalX_down { from { transform: translateX(calc(50vw - min(5vw, 28px) - clamp(50px, 8.5vw, 70px))); } to { transform: translateX(0); } }
                    @keyframes medalY_up   { from { transform: translateY(0) scale(1); } to { transform: translateY(calc(-85vh + 90px + clamp(50px, 8.5vw, 70px))) scale(1.15); } }
                    @keyframes medalY_down { from { transform: translateY(calc(-85vh + 90px + clamp(50px, 8.5vw, 70px))) scale(1.15); } to { transform: translateY(0) scale(1); } }
                    @keyframes recordFly {
                        0%   { opacity: 0; transform: translateX(-50%) scale(0.3); }
                        15%  { opacity: 1; transform: translateX(-50%) scale(1.2); }
                        60%  { opacity: 1; transform: translateX(-50%) scale(1); }
                        100% { opacity: 0; transform: translateX(calc(-50% + 35vw)) translateY(55vh) scale(0.7); }
                    }
                    @keyframes coinPop {
                        0%   { transform: scale(1);   }
                        30%  { transform: scale(1.5); }
                        60%  { transform: scale(0.9); }
                        100% { transform: scale(1);   }
                    }
                `}</style>
            </div>

            {/* ── AuthModal (глобальный — lobby, leaderboard, prizes) ────── */}
            {isAuthModalOpen && !isDead && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 3500,
                    backgroundColor: 'rgba(0,0,0,0.65)',
                    backdropFilter: 'blur(8px)',
                    WebkitBackdropFilter: 'blur(8px)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    padding: '20px', pointerEvents: 'auto',
                }}>
                    <ScreenFade />
                    <AuthModal
                        onClose={closeAuthModal}
                        onAuth={(email) => { setAuth(true); closeAuthModal(); }}
                    />
                </div>
            )}

        </>
    );
}