import { useGLTF } from '@react-three/drei'
import { sharedChickenMaterial } from '../View/sharedMaterial'

export default function Fried({ material, visible, ...props }) {
    const { nodes } = useGLTF('/models/fried.glb')
    return (
        <group visible={visible} {...props} dispose={null}>
            <mesh
                geometry={nodes.fried.geometry}
                material={material ?? sharedChickenMaterial}
            />
        </group>
    )
}

useGLTF.preload('/models/fried.glb')
