import * as THREE from 'three';
import { shaderMaterial } from '@react-three/drei';
import { extend } from '@react-three/fiber';
import { WATER_Y, WATER_ROW_WIDTH, RIPPLE_SLOTS } from '../Logic/constants';

// ── Shared ripple pool ───────────────────────────────────────────────────────
const _rippleVecs = Array.from({ length: RIPPLE_SLOTS },
    () => new THREE.Vector4(0, 0, -9999, 0));
let _rippleIdx   = 0;
let _currentTime = 0;

export const rippleArray  = _rippleVecs;
export const setWaterTime = (t) => { _currentTime = t; };

export const emitRipple = (x, z) => {
    const idx = _rippleIdx % RIPPLE_SLOTS;
    _rippleIdx++;
    _rippleVecs[idx].set(x, z, _currentTime, 0);
};

export { WATER_Y };

// ── Shared geometry (WATER_ROW_WIDTH wide × 1 deep) ─────────────────────────
export const waterRowGeometry = new THREE.PlaneGeometry(WATER_ROW_WIDTH, 1, 1, 1);

// ── Shared vertex shader (world-space position, instancing-aware) ────────────
const WORLD_POS_VERTEX = /* glsl */`
varying vec3 vWorldPos;

void main() {
    #ifdef USE_INSTANCING
    vec4 world = instanceMatrix * vec4(position, 1.0);
    #else
    vec4 world = modelMatrix * vec4(position, 1.0);
    #endif
    vWorldPos   = world.xyz;
    gl_Position = projectionMatrix * viewMatrix * world;
}
`;

// ── Material ─────────────────────────────────────────────────────────────────
const WaterRowMaterial = shaderMaterial(
    {
        uTime:    0,
        uRipples: _rippleVecs,
    },

    // ═══════ VERTEX ═══════
    WORLD_POS_VERTEX,

    // ═══════ FRAGMENT ═══════
    /* glsl */`
uniform float uTime;
uniform vec4  uRipples[${RIPPLE_SLOTS}];

varying vec3 vWorldPos;

void main() {
    vec2 wp = vWorldPos.xz;

    // ── Base waves: 4 directions, seamless across rows ───────────────────────
    float w1 = sin(dot(wp, vec2( 1.00,  0.28)) * 1.7 + uTime * 1.15) * 0.5 + 0.5;
    float w2 = sin(dot(wp, vec2( 0.35,  1.00)) * 2.3 - uTime * 0.85) * 0.5 + 0.5;
    float w3 = sin(dot(wp, vec2(-0.65,  0.75)) * 1.2 + uTime * 0.65 + 1.9) * 0.5 + 0.5;
    float w4 = sin(dot(wp, vec2( 0.80, -0.45)) * 3.1 - uTime * 1.40 + 0.7) * 0.5 + 0.5;
    float wave = w1 * 0.35 + w2 * 0.30 + w3 * 0.22 + w4 * 0.13;

    // ── Player ripples ───────────────────────────────────────────────────────
    float rip = 0.0;
    for (int i = 0; i < ${RIPPLE_SLOTS}; i++) {
        vec4  r   = uRipples[i];
        if (r.z < -100.0) continue;
        float age = uTime - r.z;
        if (age < 0.0 || age > 2.2) continue;
        float d   = length(wp - r.xy);
        float fad = pow(max(0.0, 1.0 - age / 2.0), 1.6);
        rip += (1.0 - smoothstep(0.0, 0.1, abs(d - age * 1.2)))  * fad;
        rip += (1.0 - smoothstep(0.0, 0.09, abs(d - age * 0.85))) * fad * 0.65;
        rip += (1.0 - smoothstep(0.0, 0.08, abs(d - age * 0.6))) * fad * 0.35;
    }
    rip = clamp(rip, 0.0, 1.0);

    // ── Final color ──────────────────────────────────────────────────────────
    vec3 tint = vec3(0.06, 0.72, 0.55);
    tint = mix(tint, vec3(0.75, 1.0, 0.95), pow(wave, 1.2) * 0.15);

    vec3 ripCol = mix(tint, vec3(1.0), rip * 0.85);
    float alpha = 0.22 + rip * 0.58;

    gl_FragColor = vec4(ripCol, clamp(alpha, 0.45, 1.25));
}
`
);

extend({ WaterRowMaterial });

export default WaterRowMaterial;
